VALUES
  ('retired-8b44517b-moex-00350', 'retired-8b44517b', 'retired-8b44517b-moex-110-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '依行政程序法之規定與實務見解，關於行政契約之敘述，下列何者正確？', '["替代行政處分之行政契約，如與其內容相同之行政處分有得撤銷之違法原因，並為締約之一方 所明知者，為無效", "行政契約當事人一方之人民約定自願接受執行時，該約定均應經締約行政機關之上級機關之認 可，始生效力", "中央健康保險署對於與其有全民健康保險特約之醫事服務機構所為之停止特約，實務上認係契 約行為", "行政機關依法應以甄選決定行政契約當事人一方之人民時，如於決定前未給予參與甄選者表示 意見之機會，該行政契約無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00351', 'retired-8b44517b', 'retired-8b44517b-moex-110-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '關於行政事實行為，下列敘述何者正確？', '["行政事實行為不發生法律效果，行政機關得依職權為之，不受法規規定之限制", "人民不服行政事實行為，單純拒絕即為已足，若提起行政訴訟即無權利保護必要", "行政事實行為違法侵害人民權益者，人民得向行政機關請求國家賠償", "行政事實行為僅受公法規範之拘束"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00352', 'retired-8b44517b', 'retired-8b44517b-moex-110-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '有關行政罰之裁處時效，原處罰因訴願被撤銷，而須另為裁處，其裁處時效期間應如何起算？', '["自原裁處之日起算", "自原裁處被撤銷確定之日起算", "自違反行為之日起算", "自原裁處被撤銷之日起算"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00353', 'retired-8b44517b', 'retired-8b44517b-moex-110-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '有關代履行之敘述，下列何者正確？', '["代履行係對於公法上可代替行為義務不履行之行政執行手段", "代履行之執行機關為行政執行分署", "代履行得採取斷水斷電之方式來執行", "若代履行無效果，應對義務人科處怠金 13730"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00354', 'retired-8b44517b', 'retired-8b44517b-moex-110-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '有關行政規則之敘述，下列何者錯誤？', '["行政規則，係指上級對下級機關為規範機關內部秩序及運作所為之規定", "行政規則，乃係非直接對外發生法規範效力之一般、抽象規定", "屬解釋性規定之行政規則，因僅具內部效力，程序上只需下達下級機關或屬官", "行政規則，亦包括行政機關為行使裁量權而訂定之裁量基準"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00355', 'retired-8b44517b', 'retired-8b44517b-moex-110-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '環保團體對於環境主管機關提出空氣污染問題之陳情，依行政程序法之規定，下列敘述何者正確？', '["人民之陳情，必須具明理由並限於以書面方式提出", "應向其他機關進行陳情者，非該機關即可不予理會", "無論陳情內容為何，一旦受理陳情後應舉行公聽會", "對於業已適當處理並明確回覆後，而仍一再陳情者，得不予處理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00356', 'retired-8b44517b', 'retired-8b44517b-moex-110-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '關於訴願法之敘述，下列何者錯誤？', '["處分機關未告知救濟期間，致相對人遲誤者，如自處分書送達後1年內聲明不服時，視為於法 定期間內所為", "提起訴願逾法定期間者，應為不受理之決定", "訴願人誤向訴願管轄機關以外之機關作不服原行政處分之表示者，應為不受理之決定", "訴願之提起，應自行政處分達到或公告期滿之次日起30日內為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00357', 'retired-8b44517b', 'retired-8b44517b-moex-110-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '有關行政自我拘束原則之敘述，下列何者為錯誤？', '["得自平等原則導出", "只要有行政慣例之存在，即有行政自我拘束原則之適用", "行政機關適用構成要件用語明確之羈束條款時，不適用之", "行政機關有正當理由時，得為與行政先例不一致之決定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00358', 'retired-8b44517b', 'retired-8b44517b-moex-110-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '關於行政法院對於行政處分之審查，下列敘述何者錯誤？', '["對於具有高度屬人性之評定，得審查是否出於錯誤之事實認定", "對於具有高度屬人性之評定，採取較低密度之審查", "對於具有高度屬人性之評定，得審查作成程序之合法性", "對於具有高度屬人性之評定，得審查其合法性與妥當性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00359', 'retired-8b44517b', 'retired-8b44517b-moex-110-3082b5f1', 'sub-retired-8b44517b-06', NULL, 'single_choice', '關於國家賠償法，下列敘述何者正確？', '["國家負損害賠償責任者，以回復原狀為原則", "賠償請求權之消滅時效期間，自請求權人實際知悉賠償義務機關時起算", "因公共設施之管理有欠缺所生之國家賠償責任，以管理機關有過失為必要", "於請求損害賠償時，法院得依聲請為假處分，命賠償義務機關暫先支付醫療費"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:07+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "133", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL)
